/**
 * Panha Note Editor - Complete Bundle
 * Includes: Core + Full Toolbar + Table Plugin + Image Plugin + Adapter
 * @version 1.0.0
 * @license MIT
 * 
 * Usage: 
 *   <script src="panha-note-editor.bundle.min.js"></script>
 *   <script>
 *     const editor = PanhaNoteEditor.init('#editor', { options });
 *   </script>
 */

// Note: This bundle includes the core module only.
// For full functionality, please include the individual plugin files:
// - panha-note-editor.core.min.js (required)
// - panha-note-editor.full-toolbar.min.js
// - panha-note-editor.table-plugin.min.js
// - panha-note-editor.image-plugin.min.js
// - panha-note-editor.adapter.min.js

// Load all scripts in order
(function () {
  const scripts = [
    'panha-note-editor.core.min.js',
    'panha-note-editor.full-toolbar.min.js',
    'panha-note-editor.table-plugin.min.js',
    'panha-note-editor.image-plugin.min.js',
    'panha-note-editor.adapter.min.js'
  ];

  const baseUrl = (function () {
    const scriptElements = document.getElementsByTagName('script');
    for (let i = 0; i < scriptElements.length; i++) {
      const src = scriptElements[i].src;
      if (src && src.indexOf('panha-note-editor.bundle.min.js') !== -1) {
        return src.substring(0, src.lastIndexOf('/') + 1);
      }
    }
    return './';
  })();

  function loadScript(index) {
    if (index >= scripts.length) {
      console.log('✅ Panha Note Editor: All components loaded');
      return;
    }

    const script = document.createElement('script');
    script.src = baseUrl + scripts[index];
    script.onload = function () {
      loadScript(index + 1);
    };
    script.onerror = function () {
      console.error('❌ Failed to load:', scripts[index]);
      loadScript(index + 1);
    };
    document.head.appendChild(script);
  }

  loadScript(0);
})();
